final:
module top_module(
    input a,
    input b,
    input sel_b1,
    input sel_b2,
    output out
);wire invalid_mux;
wire xor_out;

// 2-to-1 Mux
assign invalid_mux = sel_b1 ? b : (sel_b2 ? a : 1'b0);

// XOR Gate
assign xor_out = a ^ b;

// Output
assign out = sel_b1 | sel_b2 ? invalid_mux : xor_out;

endmodule
